          ctx.moveTo(mx + 8 * Math.cos(angle), my + 8 * Math.sin(angle));
          ctx.lineTo(mx + 8 * Math.cos(angle + 2.5), my + 8 * Math.sin(angle + 2.5));
          ctx.lineTo(mx + 8 * Math.cos(angle - 2.5), my + 8 * Math.sin(angle - 2.5));
